     5→/** A data object representing a Jam value.
     6→  * JamVal := IntConstant | BoolConstant | JamList | JamFun */
     7→interface JamVal {
     8→  <ResType> ResType accept(JamValVisitor<ResType> jvv);
     9→}
    10→
    11→/** A visitor for the JamVal type (Jam values).  */
    12→interface JamValVisitor<ResType> {
    13→  ResType forIntConstant(IntConstant ji);
    14→  ResType forBoolConstant(BoolConstant jb);
    15→  ResType forJamList(JamList jl);
    16→  ResType forJamFun(JamFun jf);
    17→  ResType forJamRef(JamRef jr);
    18→  ResType forJamUnit(JamUnit ju);
    19→}
    20→
    21→/** JamVal classes */
    22→
    23→/** A Jam integer constant, also used to represent an integer token for parsing.  */
    24→class IntConstant implements Token, Constant, JamVal {
    25→  private int value;
    26→  
    27→  IntConstant(int i) { value = i; }
    28→  // duplicates can occur!
    29→  
    30→  public int value() { return value; }
    31→  
    32→  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forIntConstant(this); }
    33→  public <ResType> ResType accept(JamValVisitor<ResType> v) { return v.forIntConstant(this); }
    34→  /** redefines equals so that equal integers are recognized as equal */
    35→  public boolean equals(Object other) {
    36→    return (other != null && this.getClass() == other.getClass()) && 
    37→      (value == ((IntConstant)other).value());
    38→  }
    39→  /** computes the obvious hashcode for this consistent with equals. */
    40→  public int hashcode() { return value; }
    41→  public String toString() { return String.valueOf(value); }
    42→}
