    44→/** A Jam boolean constant, also used to represent a boolean token for parsing. */
    45→class BoolConstant implements Token, Constant, JamVal {
    46→  private boolean value;
    47→  private BoolConstant(boolean b) { value = b; }
    48→  
    49→  /** Singleton pattern definitions. */
    50→  public static final BoolConstant FALSE = new BoolConstant(false);
    51→  public static final BoolConstant TRUE = new BoolConstant(true);
    52→  
    53→  /** A factory method that returns BoolConstant corresponding to b. It is atatic because
    54→    * it does not depend on this. */
    55→  public static BoolConstant toBoolConstant(boolean b) { 
    56→    if (b) return TRUE; 
    57→    else return FALSE;
    58→  }
    59→  
    60→  public boolean value() { return value; }
    61→  public BoolConstant not() { if (this == FALSE) return TRUE; else return FALSE; }
    62→  
    63→  public <ResType> ResType accept(ASTVisitor<ResType> av) { return av.forBoolConstant(this); }
    64→  public <ResType> ResType accept(JamValVisitor<ResType> jv) { return jv.forBoolConstant(this); }
    65→  public String toString() { return String.valueOf(value); }
    66→}
