   137→  private AST parseIf() {
   138→    
   139→    AST test = parseExp();
   140→    Token key1 = in.readToken();
   141→    if (key1 != Lexer.THEN) error(key1,"`then'");
   142→    AST conseq = parseExp();
   143→    Token key2 = in.readToken();
   144→    if (key2 != Lexer.ELSE) error(key2,"`else'");
   145→    AST alt = parseExp();
   146→    return new If(test,conseq,alt);
