    return (o instanceof RefType) && elemType.equals(((RefType) o).elemType);
  }
  public int hashCode() { return 5 + elemType.hashCode(); }
}

/** Type representing a function with given parameter types and result type. */
class FunType implements Type {
  private Type[] paramTypes;
  private Type resultType;
  FunType(Type[] ps, Type r) { paramTypes = ps; resultType = r; }
  public Type[] paramTypes() { return paramTypes; }
  public Type resultType() { return resultType; }
  public String toString() {
    if (paramTypes.length == 0) return "( -> " + resultType + ")";
    StringBuilder sb = new StringBuilder("(");
    sb.append(paramTypes[0]);
    for (int i = 1; i < paramTypes.length; i++) sb.append(", ").append(paramTypes[i]);
    sb.append(" -> ").append(resultType).append(")");
    return sb.toString();
  }
  public boolean equals(Object o) {
    if (!(o instanceof FunType)) return false;
    FunType ft = (FunType) o;
    if (paramTypes.length != ft.paramTypes.length) return false;
    for (int i = 0; i < paramTypes.length; i++) {
      if (!paramTypes[i].equals(ft.paramTypes[i])) return false;
    }
    return resultType.equals(ft.resultType);
  }
  public int hashCode() {
    int h = resultType.hashCode();
    for (Type p : paramTypes) h = h * 37 + p.hashCode();
    return h;
  }
}

/* ===== Typed AST Nodes ===== */

/** A typed empty list constant with an explicit element type annotation (empty : Type). */
class TypedEmpty implements Constant {
  private Type elemType;
  public TypedEmpty(Type t) { elemType = t; }
  public Type elemType() { return elemType; }
  public <T> T accept(ASTVisitor<T> v) { return v.forTypedEmpty(this); }
  public String toString() { return "empty:" + elemType; }
}

/** A typed definition that associates a variable with a declared type in a let expression. */
class TypedDef extends Def {
  private Type varType;
  TypedDef(Variable lhs, Type t, AST rhs) {
    super(lhs, rhs);
    varType = t;
  }
  public Type varType() { return varType; }
  public String toString() { return lhs() + ":" + varType + " := " + rhs() + ";"; }
}

/** A typed map expression whose parameters each have an explicit type annotation. */
class TypedMap extends Map {
  private Type[] varTypes;
  TypedMap(Variable[] vars, Type[] types, AST body) {
    super(vars, body);
    varTypes = types;
  }
  public Type[] varTypes() { return varTypes; }
}

