/** Parser for Typed Jam (Assignment 5).
 *  Supports type annotations on variable bindings and map parameters,
 *  typed empty lists, and restricts primitive operations to those typeable
 *  in a conventional static type system.
 */

import java.io.*;
import java.util.*;

/** Class that represented parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
  ParseException(Throwable t) { super(t); }
}

class Parser {

  private Lexer in;

  Parser(Lexer i) { in = i; }

  Parser(Reader inputStream) { this(new Lexer(inputStream)); }

  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }

  Lexer lexer() { return in; }

  public void initParser() { }

  /** Parses the program in the Lexer associated with this. */
  public AST parse() throws ParseException {
    try {
      in.reset();
      AST prog = parseExp();
      Token t = in.readToken();
      if (t == EndOfFile.ONLY) return prog;
      else throw new ParseException("Legal program followed by extra token " + t);
    }
    finally {
      try { in.rdr.close(); }
      catch (IOException e) { throw new ParseException(e); }
    }
  }

  /** Parses and syntactically checks the program in the Lexer associated with this. */
  public AST parseAndCheck() throws ParseException {
    AST prog = parseExp();
    Token t = in.readToken();
    if (t != EndOfFile.ONLY) throw new ParseException("Legal program '" + prog + "'followed by extra token " + t);

    /* Invoke the CheckVisitor to confirm prog does not contain free variables or duplicate names. */
    prog.accept(CheckVisitor.INITIAL);   // aborts on an error by throwing an exception
    return prog;
  }

  /** Parses:
    *   <exp> ::= if <exp> then <exp> else <exp>
    *           | let <prop-def-list> in <exp>
    *           | map TypedIdList to <exp>
    *           | { PropStatementList }
    *           | <term> { <binop> <term> }*
    */
  private AST parseExp() {
    Token token = in.readToken();

    if (token == Lexer.IF) return parseIf();
    if (token == Lexer.LET) return parseLet();
    if (token == Lexer.MAP) return parseMap();

    /* Supports the addition of blocks to Jam */
    if (token == LeftBrace.ONLY) {
      AST[] exps = parseExps(SemiColon.ONLY, RightBrace.ONLY);
      if (exps.length == 0) throw new ParseException("Illegal empty block");
      return new Block(exps);
    }

    /* phrase begins with a term */
    AST exp = parseTerm(token);

    Token next = in.peek();
    while (next instanceof OpToken) {
      OpToken op = (OpToken) next;
      in.readToken(); // remove next from input stream
      if (!op.isBinOp()) error(next, "binary operator");
      AST newTerm = parseTerm(in.readToken());
      exp = new BinOpApp(op.toBinOp(), exp, newTerm);
      next = in.peek();
    }
    return exp;
  }

  /** Parses:
    *   <term> ::= <unop> <term>
    *            | <factor> { ( <exp-list> ) }
    *            | <prim> ( <exp-list> )
    *            | empty : <type>
    *            | <int>
    *            | <bool>
    * @param token first token in input stream to be parsed; remainder in Lexer named in.
    */
  private AST parseTerm(Token token) {

    /* Handle unary operators (including ref) */
    if (token instanceof OpToken) {
      OpToken op = (OpToken) token;
      if (!op.isUnOp()) error(op, "unary operator");
      return new UnOpApp(op.toUnOp(), parseTerm(in.readToken()));
    }

    /* Handle empty : Type */
    if (token == EmptyConstant.ONLY) {
      Token colon = in.readToken();
      if (colon != Colon.ONLY) error(colon, "':'");
      Type elemType = parseType();
      return new TypedEmpty(elemType);
    }

    /* Handle other constants (Int, Bool) */
    if (token instanceof Constant) return (Constant) token;

    /* Handle Prim — must be followed by argument list in typed Jam */
    if (token instanceof PrimFun) {
      PrimFun pf = (PrimFun) token;
      /* Reject primitives eliminated from typed Jam */
      if (pf instanceof FunctionPPrim || pf instanceof NumberPPrim ||
          pf instanceof ListPPrim || pf instanceof RefPPrim || pf instanceof ArityPrim) {
        throw new ParseException("Primitive '" + pf + "' is not allowed in typed Jam");
      }
      /* Valid prims: cons, first, rest, empty?, cons? — require argument list */
      Token next = in.peek();
      if (next != LeftParen.ONLY) error(next, "'(' after primitive '" + pf + "'");
      in.readToken(); // consume '('
      AST[] args = parseArgs();
      return new App(pf, args);
    }

    /* Handle Factor { ( ExpList ) } */
    AST factor = parseFactor(token);
    Token next = in.peek();
    if (next == LeftParen.ONLY) {
      in.readToken(); // consume '('
      AST[] exps = parseArgs();
      return new App(factor, exps);
    }
    return factor;
  }

  /** Parses: <factor> ::= ( <exp> ) | <id>
    * @param token first token in input stream to be parsed; remainder in Lexer named in.
    */
  private AST parseFactor(Token token) {

    if (token == LeftParen.ONLY) {
      /* Parse a parenthesized expression */
      AST exp = parseExp();
      token = in.readToken();
      if (token != RightParen.ONLY) error(token, "')'");
      return exp;
    }

    if (!(token instanceof Variable))
      error(token, "variable or '('");

    return (Variable) token;
  }

  /** Parses 'if <exp> then <exp> else <exp>' given that 'if' has already been read. */
  private AST parseIf() {
    AST test = parseExp();
    Token key1 = in.readToken();
    if (key1 != Lexer.THEN) error(key1, "'then'");
    AST conseq = parseExp();
    Token key2 = in.readToken();
    if (key2 != Lexer.ELSE) error(key2, "'else'");
    AST alt = parseExp();
    return new If(test, conseq, alt);
  }

  /** Parses 'let <prop-def-list> in <exp>' given that 'let' has already been read. */
  private AST parseLet() {
    Def[] defs = parseDefs();
    AST body = parseExp();
    return new Let(defs, body);
  }

  /** Parses 'map TypedIdList to <exp>' given that 'map' has already been read. */
  private AST parseMap() {
    LinkedList<Variable> vars = new LinkedList<Variable>();
    LinkedList<Type> types = new LinkedList<Type>();

    Token t = in.readToken();
    if (t == Lexer.TO) {
      /* Empty parameter list */
      AST body = parseExp();
      return new TypedMap(new Variable[0], new Type[0], body);
    }

    /* Parse first TypedId: Id : Type */
    do {
      if (!(t instanceof Variable)) error(t, "variable in map parameter list");
      vars.addLast((Variable) t);
      Token colon = in.readToken();
      if (colon != Colon.ONLY) error(colon, "':'");
      types.addLast(parseType());
      t = in.readToken();
      if (t == Lexer.TO) break;
      if (t != Comma.ONLY) error(t, "',' or 'to'");
      t = in.readToken();
    } while (true);

    AST body = parseExp();
    return new TypedMap(
      vars.toArray(new Variable[0]),
      types.toArray(new Type[0]),
      body
    );
  }

  /** Parses '<exp-list> <delim>' where
    *  <exp-list>      ::= <empty> | <prop-exp-list>
    *  <prop-exp-list> ::= <exp> | <exp> <separator> <prop-exp-list>
    */
  private AST[] parseExps(Token separator, Token delim) {
    LinkedList<AST> exps = new LinkedList<AST>();
    Token next = in.peek();

    if (next == delim) {
      in.readToken(); // consume delimiter
      return new AST[0];
    }

    do {
      AST exp = parseExp();
      exps.addLast(exp);
      next = in.readToken();
    } while (next == separator);

    if (next != delim) error(next, "'" + separator + "' or '" + delim + "'");
    return exps.toArray(new AST[0]);
  }

  private AST[] parseArgs() { return parseExps(Comma.ONLY, RightParen.ONLY); }

  /** Parses a proper list of TypedDefs (Id : Type := Exp ;), consuming 'in' at the end. */
  private Def[] parseDefs() {
    LinkedList<Def> defs = new LinkedList<Def>();
    Token t = in.readToken();

    do {
      Def d = parseDef(t);
      defs.addLast(d);
      t = in.readToken();
    } while (t != Lexer.IN);

    return defs.toArray(new Def[0]);
  }

  /** Parses 'Id : Type := Exp ;' given that the first token (var) has been read. */
  private Def parseDef(Token var) {
    if (!(var instanceof Variable)) error(var, "variable");

    Token colon = in.readToken();
    if (colon != Colon.ONLY) error(colon, "':'");

    Type varType = parseType();

    Token bind = in.readToken();
    if (bind != Lexer.BIND) error(bind, "':='");

    AST exp = parseExp();

    Token semi = in.readToken();
    if (semi != SemiColon.ONLY) error(semi, "';'");

    return new TypedDef((Variable) var, varType, exp);
  }

  /** Parses a Type expression:
    *   Type ::= unit | int | bool | list Type | ref Type | (TypeList -> Type)
    *   TypeList ::= { PropTypeList }
    *   PropTypeList ::= Type | Type , PropTypeList
    */
  private Type parseType() {
    Token t = in.readToken();

    if (t == Lexer.UNIT) return UnitType.ONLY;
    if (t == Lexer.INT)  return IntType.ONLY;
    if (t == Lexer.BOOL) return BoolType.ONLY;

    if (t == Lexer.LIST) return new ListType(parseType());

    /* ref Type — 'ref' is an OpToken (REF) in the lexer */
    if (t == Lexer.REF) return new RefType(parseType());

    /* (TypeList -> Type) */
    if (t == LeftParen.ONLY) {
      LinkedList<Type> paramTypes = new LinkedList<Type>();

      /* Check if TypeList is non-empty (peek for '-' which starts '->') */
      Token next = in.peek();
      if (next != Lexer.MINUS) {
        /* Parse first type */
        paramTypes.addLast(parseType());
        next = in.peek();
        /* Parse additional types separated by commas */
        while (next == Comma.ONLY) {
          in.readToken(); // consume ','
          paramTypes.addLast(parseType());
          next = in.peek();
        }
      }

      /* Consume '->' (two tokens: MINUS then GREATER_THAN) */
      Token arrow1 = in.readToken();
      if (arrow1 != Lexer.MINUS) error(arrow1, "'->'");
      Token arrow2 = in.readToken();
      if (arrow2 != Lexer.GREATER_THAN) error(arrow2, "'>' in '->'");

      Type resultType = parseType();

      Token rparen = in.readToken();
      if (rparen != RightParen.ONLY) error(rparen, "')'");

      return new FunType(paramTypes.toArray(new Type[0]), resultType);
    }

    return (Type) error(t, "type (unit, int, bool, list, ref, or '(')");
  }

  private AST error(Token found, String expected) {
    throw new ParseException("Token '" + found + "' appears where " + expected + " was expected");
  }

  /** A legacy main method. */
  public static void main(String[] args) throws IOException {
    if (args.length == 0) return;
    Parser p = new Parser(args[0]);
    AST prog = p.parse();
  }
}

