/* ===== Type Checker for Typed Jam ===== */

/** Visitor that type-checks a Typed Jam AST.
  * Takes a type environment mapping Variables to Types and returns the Type of the expression.
  * Throws TypeException on type errors.
  */
class TypeChecker implements ASTVisitor<Type> {

  /** Type environment: maps variables to their declared types. */
  private HashMap<Variable, Type> env;

  TypeChecker(HashMap<Variable, Type> e) { env = e; }

  public Type forBoolConstant(BoolConstant b) { return BoolType.ONLY; }
  public Type forIntConstant(IntConstant i) { return IntType.ONLY; }

  public Type forEmptyConstant(EmptyConstant n) {
    throw new TypeException("Untyped 'empty' is not allowed in typed Jam; use 'empty : Type'");
  }

  public Type forTypedEmpty(TypedEmpty n) {
    return new ListType(n.elemType());
  }

  public Type forVariable(Variable v) {
    Type t = env.get(v);
    if (t == null) throw new TypeException("Unbound variable: " + v);
    return t;
  }

  public Type forPrimFun(PrimFun f) {
    throw new TypeException("Primitive '" + f + "' cannot be used as a bare value in typed Jam");
  }

  public Type forUnOpApp(UnOpApp u) {
    Type argType = u.arg().accept(this);
    return u.rator().accept(new UnOpTypeChecker(argType));
  }

  public Type forBinOpApp(BinOpApp b) {
    Type t1 = b.arg1().accept(this);
    Type t2 = b.arg2().accept(this);
    return b.rator().accept(new BinOpTypeChecker(t1, t2));
  }

  public Type forApp(App a) {
    AST rator = a.rator();
    /* Primitive application */
    if (rator instanceof PrimFun) {
      return checkPrimApp((PrimFun) rator, a.args());
    }
    /* General function application */
    Type ratorType = rator.accept(this);
    if (!(ratorType instanceof FunType))
      throw new TypeException("Operator in application is not a function type, got: " + ratorType);
    FunType ft = (FunType) ratorType;
    AST[] args = a.args();
    Type[] paramTypes = ft.paramTypes();
    if (paramTypes.length != args.length)
      throw new TypeException("Wrong number of arguments: expected " + paramTypes.length + " but got " + args.length);
    for (int i = 0; i < args.length; i++) {
      Type argType = args[i].accept(this);
      if (!argType.equals(paramTypes[i]))
        throw new TypeException("Argument " + i + " type mismatch: expected " + paramTypes[i] + " but got " + argType);
    }
    return ft.resultType();
  }

  public Type forMap(Map m) {
    if (!(m instanceof TypedMap))
      throw new TypeException("Untyped map not allowed in typed Jam");
    TypedMap tm = (TypedMap) m;
    Variable[] vars = tm.vars();
    Type[] paramTypes = tm.varTypes();
    HashMap<Variable, Type> newEnv = new HashMap<Variable, Type>(env);
    for (int i = 0; i < vars.length; i++) {
      newEnv.put(vars[i], paramTypes[i]);
    }
    Type bodyType = tm.body().accept(new TypeChecker(newEnv));
    return new FunType(paramTypes, bodyType);
  }

  public Type forIf(If i) {
    Type testType = i.test().accept(this);
    if (!testType.equals(BoolType.ONLY))
      throw new TypeException("if condition must have type bool, but has type " + testType);
    Type conseqType = i.conseq().accept(this);
    Type altType = i.alt().accept(this);
    if (!conseqType.equals(altType))
      throw new TypeException("if branches must have the same type, but got " + conseqType + " and " + altType);
    return conseqType;
  }

  public Type forLet(Let l) {
    Def[] defs = l.defs();
    Variable[] vars = l.vars();
    /* Build new environment including all let-bound variables with their declared types */
    HashMap<Variable, Type> newEnv = new HashMap<Variable, Type>(env);
    for (int i = 0; i < defs.length; i++) {
      if (!(defs[i] instanceof TypedDef))
        throw new TypeException("Untyped definition in let; use 'Id : Type := Exp'");
      TypedDef td = (TypedDef) defs[i];
      newEnv.put(vars[i], td.varType());
    }
    TypeChecker newChecker = new TypeChecker(newEnv);
    /* Check each RHS type matches the declared type (recursive let) */
    for (int i = 0; i < defs.length; i++) {
      TypedDef td = (TypedDef) defs[i];
      Type rhsType = td.rhs().accept(newChecker);
      if (!rhsType.equals(td.varType()))
        throw new TypeException("Type mismatch in definition of '" + vars[i] +
          "': declared " + td.varType() + " but expression has type " + rhsType);
    }
    return l.body().accept(newChecker);
  }

  public Type forBlock(Block b) {
    AST[] exps = b.exps();
    Type lastType = null;
    for (AST exp : exps) {
      lastType = exp.accept(this);
    }
    return lastType;
  }

  /** Type-checks an application of a primitive function. */
  private Type checkPrimApp(PrimFun pf, final AST[] args) {
    return pf.accept(new PrimFunVisitor<Type>() {

      public Type forConsPrim() {
        if (args.length != 2)
          throw new TypeException("cons requires 2 arguments, got " + args.length);
        Type t1 = args[0].accept(TypeChecker.this);
        Type t2 = args[1].accept(TypeChecker.this);
        if (!(t2 instanceof ListType))
          throw new TypeException("Second argument to cons must have a list type, got " + t2);
        ListType lt = (ListType) t2;
        if (!t1.equals(lt.elemType()))
          throw new TypeException("Type mismatch in cons: element type " + lt.elemType() +
            " but first argument has type " + t1);
        return lt;
      }

      public Type forFirstPrim() {
        if (args.length != 1)
          throw new TypeException("first requires 1 argument, got " + args.length);
        Type t = args[0].accept(TypeChecker.this);
        if (!(t instanceof ListType))
          throw new TypeException("first applied to non-list type " + t);
        return ((ListType) t).elemType();
      }

      public Type forRestPrim() {
        if (args.length != 1)
          throw new TypeException("rest requires 1 argument, got " + args.length);
        Type t = args[0].accept(TypeChecker.this);
        if (!(t instanceof ListType))
          throw new TypeException("rest applied to non-list type " + t);
        return t;
      }

      public Type forEmptyPPrim() {
        if (args.length != 1)
          throw new TypeException("empty? requires 1 argument, got " + args.length);
        Type t = args[0].accept(TypeChecker.this);
        if (!(t instanceof ListType))
          throw new TypeException("empty? applied to non-list type " + t);
        return BoolType.ONLY;
      }

      public Type forConsPPrim() {
        if (args.length != 1)
          throw new TypeException("cons? requires 1 argument, got " + args.length);
        Type t = args[0].accept(TypeChecker.this);
        if (!(t instanceof ListType))
          throw new TypeException("cons? applied to non-list type " + t);
        return BoolType.ONLY;
      }

      /* The following primitives are not allowed in typed Jam */
      public Type forFunctionPPrim() { throw new TypeException("function? not allowed in typed Jam"); }
      public Type forNumberPPrim()   { throw new TypeException("number? not allowed in typed Jam"); }
      public Type forListPPrim()     { throw new TypeException("list? not allowed in typed Jam"); }
      public Type forArityPrim()     { throw new TypeException("arity not allowed in typed Jam"); }
      public Type forRefPPrim()      { throw new TypeException("ref? not allowed in typed Jam"); }
    });
  }
}

/** Type checker visitor for unary operators. */
class UnOpTypeChecker implements UnOpVisitor<Type> {
  private Type argType;
  UnOpTypeChecker(Type t) { argType = t; }

  public Type forUnOpPlus() {
    if (!argType.equals(IntType.ONLY))
      throw new TypeException("Unary '+' requires int, got " + argType);
    return IntType.ONLY;
  }

  public Type forUnOpMinus() {
    if (!argType.equals(IntType.ONLY))
      throw new TypeException("Unary '-' requires int, got " + argType);
    return IntType.ONLY;
  }

  public Type forOpTilde() {
    if (!argType.equals(BoolType.ONLY))
      throw new TypeException("'~' requires bool, got " + argType);
    return BoolType.ONLY;
  }

  public Type forOpBang() {
    if (!(argType instanceof RefType))
      throw new TypeException("'!' requires ref type, got " + argType);
    return ((RefType) argType).elemType();
  }

  public Type forOpRef() {
    return new RefType(argType);
  }
}

/** Type checker visitor for binary operators. */
class BinOpTypeChecker implements BinOpVisitor<Type> {
  private Type t1, t2;
  BinOpTypeChecker(Type t1, Type t2) { this.t1 = t1; this.t2 = t2; }

  private void requireInt(Type t, String op) {
    if (!t.equals(IntType.ONLY))
      throw new TypeException("Operator '" + op + "' requires int, got " + t);
  }

  private void requireBool(Type t, String op) {
    if (!t.equals(BoolType.ONLY))
      throw new TypeException("Operator '" + op + "' requires bool, got " + t);
  }

  public Type forBinOpPlus()           { requireInt(t1, "+"); requireInt(t2, "+"); return IntType.ONLY; }
  public Type forBinOpMinus()          { requireInt(t1, "-"); requireInt(t2, "-"); return IntType.ONLY; }
  public Type forOpTimes()             { requireInt(t1, "*"); requireInt(t2, "*"); return IntType.ONLY; }
  public Type forOpDivide()            { requireInt(t1, "/"); requireInt(t2, "/"); return IntType.ONLY; }
  public Type forOpLessThan()          { requireInt(t1, "<"); requireInt(t2, "<"); return BoolType.ONLY; }
  public Type forOpGreaterThan()       { requireInt(t1, ">"); requireInt(t2, ">"); return BoolType.ONLY; }
  public Type forOpLessThanEquals()    { requireInt(t1, "<="); requireInt(t2, "<="); return BoolType.ONLY; }
  public Type forOpGreaterThanEquals() { requireInt(t1, ">="); requireInt(t2, ">="); return BoolType.ONLY; }
  public Type forOpAnd()               { requireBool(t1, "&"); requireBool(t2, "&"); return BoolType.ONLY; }
  public Type forOpOr()                { requireBool(t1, "|"); requireBool(t2, "|"); return BoolType.ONLY; }

  public Type forOpEquals() {
    if (!t1.equals(t2))
      throw new TypeException("'=' requires operands of the same type, got " + t1 + " and " + t2);
    return BoolType.ONLY;
  }

  public Type forOpNotEquals() {
    if (!t1.equals(t2))
      throw new TypeException("'!=' requires operands of the same type, got " + t1 + " and " + t2);
    return BoolType.ONLY;
  }

  public Type forOpGets() {
    /* '<- : ref 'a, 'a -> unit' */
    if (!(t1 instanceof RefType))
      throw new TypeException("'<-' requires a ref type on the left, got " + t1);
    RefType rt = (RefType) t1;
    if (!t2.equals(rt.elemType()))
      throw new TypeException("'<-' type mismatch: ref element type is " + rt.elemType() + " but right side has type " + t2);
    return UnitType.ONLY;
  }
}
